func jobBackURL(job *JobContextView) string {
	if job.TaskID != "" {
		return "/tasks/" + job.TaskID
	}
	if job.ProjectID != "" {
		return "/sessions"
	}
	return "/"
}

// jobStatusStripe maps a job status to the task-row-status-* class so the
// detail header reuses the task list's left-edge colour palette.
//
//	pending   → slate (same as task pending)
//	running   → green (same as task executing)
//	completed → gray  (same as task done)
//	failed    → red   (same as task aborted)
func jobStatusStripe(status string) string {
	switch status {
	case "running":
		return "task-row-status-executing"
	case "completed":
		return "task-row-status-done"
	case "failed":
		return "task-row-status-aborted"
	default:
		return "task-row-status-pending"
	}
}

// jobPageTitle builds the page-header title from the job's identity.
// DisplayName (hook's `name` property) is preferred over HandlerID when set,
// mirroring BuildJobLabel / timelineJobIdentity in the timeline package.
// Hook jobs omit the [hook] prefix.
func jobPageTitle(job *JobContextView) string {
	label := job.DisplayName
	if label == "" {
		label = job.HandlerID
	}
	if job.Role == "hook" {
		if label != "" {
			return label
		}
		return "Job " + shortID(job.ID)
	}
	switch {
	case job.Role != "" && label != "":
		return "[" + job.Role + "] " + label
	case label != "":
		return label
	case job.Role != "":
		return "[" + job.Role + "]"
	default:
		return "Job " + shortID(job.ID)
	}
}

